define('NODE_CMD', 'node');
define('PARIK_SCRIPT', __DIR__ . DIRECTORY_SEPARATOR . 'match_totals.js');
define('PINN_SCRIPT', __DIR__ . DIRECTORY_SEPARATOR . 'match_totals_pinnacle.js');

if ($_SERVER['REQUEST_METHOD'] !== 'POST') {
    respond(false, 'Method not allowed');
}

$parikUrl = trim($_POST['parikUrl'] ?? '');
$pinnUrl  = trim($_POST['pinnUrl'] ?? '');
$proxy    = trim($_POST['proxy'] ?? ($_COOKIE['ua_proxy'] ?? ''));

if ($parikUrl === '' || $pinnUrl === '') {
    respond(false, 'parikUrl and pinnUrl are required');
}

$parikData = run_node_json(PARIK_SCRIPT, $parikUrl, $proxy);
if (!is_array($parikData) || !($parikData['ok'] ?? false)) {
    respond(false, 'Parik24 scrape failed: ' . (($parikData['error'] ?? null) ?: 'unknown'));
}
$pinData = run_node_json(PINN_SCRIPT, $pinnUrl, $proxy);
if (!is_array($pinData) || !($pinData['ok'] ?? false)) {
    respond(false, 'Pinnacle scrape failed: ' . (($pinData['error'] ?? null) ?: 'unknown'));
}

$parikTotals = normalize_totals($parikData['totals'] ?? []);
$pinTotals   = normalize_totals($pinData['totals'] ?? []);

$sharedLines = array_values(array_intersect(array_keys($parikTotals), array_keys($pinTotals)));
sort($sharedLines, SORT_NATURAL);

$rows = [];
foreach ($sharedLines as $key) {
    $p = $parikTotals[$key];
    $q = $pinTotals[$key];
    $xOver = to_float($p['over'] ?? null);
    $xUnder = to_float($p['under'] ?? null);
    $yOver = to_float($q['over'] ?? null);
    $yUnder = to_float($q['under'] ?? null);

$zOver  = ($xOver && $yUnder) ? (1/$xOver + 1/$yUnder) : null;
$zUnder = ($xUnder && $yOver) ? (1/$xUnder + 1/$yOver) : null;

    $rows[] = [
        'line' => $p['line'],
        'parik' => ['over' => $p['over'] ?? null, 'under' => $p['under'] ?? null],
        'pinnacle' => ['over' => $q['over'] ?? null, 'under' => $q['under'] ?? null],
        'zOver' => $zOver,
        'zUnder' => $zUnder,
    ];
}

