]);

function normalize_totals(array $rows): array {
    $out = [];
    foreach ($rows as $row) {
        $line = (string)($row['line'] ?? '');
        if ($line === '') continue;
        $normLine = normalize_line_key($line);
        if ($normLine === '') continue;
        $over = isset($row['over']) ? (string)$row['over'] : null;
        $under = isset($row['under']) ? (string)$row['under'] : null;
        $out[$normLine] = [
            'line' => $line,
            'over' => $over,
            'under' => $under,
        ];
    }
    return $out;
}

function normalize_line_key(string $line): string {
    $v = str_replace(',', '.', trim($line));
    if ($v === '' || !preg_match('/^\d+(\.\d+)?$/', $v)) return '';
    $n = (float)$v;
    return number_format($n, fmod($n, 1.0) === 0.0 ? 1 : 1, '.', '');
}

function to_float($v): ?float {
    if ($v === null || $v === '' || $v === '—') return null;
    $f = (float)str_replace(',', '.', (string)$v);
    return $f > 0 ? $f : null;
}

function run_node_json(string $script, string $href, string $proxy = ''): array {
    $cmd = escapeshellarg(NODE_CMD) . ' ' . escapeshellarg($script) . ' ' . escapeshellarg($href);
    if ($proxy !== '') {
        $cmd .= ' ' . '--proxy=' . escapeshellarg($proxy);
    }
    if (strtoupper(substr(PHP_OS, 0, 3)) === 'WIN') {
        $descriptorSpec = [
            0 => ['pipe', 'r'],
            1 => ['pipe', 'w'],
            2 => ['pipe', 'w'],
        ];
        $proc = proc_open($cmd, $descriptorSpec, $pipes, __DIR__);
        if (!is_resource($proc)) {
            return ['ok' => false, 'error' => 'Cannot start process'];
        }
        $out = stream_get_contents($pipes[1]);
        $err = stream_get_contents($pipes[2]);
        foreach ($pipes as $p) { @fclose($p); }
        $code = proc_close($proc);
    } else {
        $out = shell_exec($cmd . ' 2>&1') ?? '';
        $err = '';
        $code = 0;
    }
    $out = trim($out);
    $decoded = json_decode($out, true);
    if (!is_array($decoded)) {
        return ['ok' => false, 'error' => ($err ?: 'Invalid JSON from node'), 'raw' => $out];
    }
    return $decoded;
}

function respond(bool $ok, ?string $error = null, array $extra = []): void {
    $payload = array_merge([
        'ok' => $ok,
        'error' => $error,
    ], $extra);

    echo json_encode($payload, JSON_UNESCAPED_UNICODE);
    exit;
}
